const GF_T35_HALF_IMG = "data:image/png;base64,";
const GF_T31_IMG = "data:image/png;base64,";
const GF_CC_IMG = "data:image/png;base64,";
const GF_T35_FULL_IMG = "data:image/png;base64,";
const GF_DROP_OUT_IMG = "data:image/png;base64,";

const GF_ASSEMBLY_IMAGES = {
  'Close-Coupled': GF_CC_IMG,
  'Single Ended T35 Half Spacer': GF_T35_HALF_IMG,
  'Single Ended T35 Full Spacer': GF_T35_FULL_IMG,
  'Double Ended T31 Full Spacer': GF_T31_IMG,
  'Drop-In Style With Double Ended Spacer': GF_DROP_OUT_IMG,
};

function gfGetAssemblyImage(style, spacerStyle) {
  if (style === "Close-Coupled") return GF_ASSEMBLY_IMAGES["Close-Coupled"];
  return GF_ASSEMBLY_IMAGES[spacerStyle] || null;
}